class Solution {
    public String solveEquation(String equation) {
        String[] parts = equation.split("=");
        int leftX = 0, leftVal = 0, rightX = 0, rightVal = 0;
        String[] left = parts[0].split("\\+|-");
        for (String s : left) {
            if (s.equals("x")) {
                leftX++;
            } else if (s.contains("x")) {
                leftX += Integer.parseInt(s.replace("x", ""));
            } else {
                leftVal += Integer.parseInt(s);
            }
        }
        String[] right = parts[1].split("\\+|-");
        for (String s : right) {
            if (s.equals("x")) {
                rightX++;
            } else if (s.contains("x")) {
                rightX += Integer.parseInt(s.replace("x", ""));
            } else {
                rightVal += Integer.parseInt(s);
            }
        }
        leftVal = -leftVal + rightVal;
        leftX = leftX - rightX;
        if (leftX == 0 && leftVal == 0) {
            return "Infinite solutions";
        } else if (leftX == 0) {
            return "No solution";
        } else {
            return "x=" + leftVal / leftX;
        }
    }
}
